public Complex add(Complex rhs) {
  return new Complex(real + rhs.real, imaginary + rhs.imaginary);
}

public static Vector3D crossProduct(Vector3D v1, Vector3D v2) {
  return new Vector3D(v1.y*v2.z - v1.z*v2.y, v1.z*v2.x - v1.x*v2.z, v1.x*v2.y - v1.y*v2.x);
}

public Line revert() {
  return new Line(zero, zero.subtract(direction));
}

public String generateToolTipFragment(String toolTipText) {
  return " title=" + toolTipText + " alt=";
}

public boolean equals(Object obj) {
  if (obj == this) return true;
  if (!(obj instanceof XYPlot)) return false;
  XYPlot that = (XYPlot) obj;
  return this.weight == that.weight && this.orientation == that.orientation;
}

public Date parse(String source) throws ParseException {
  ParsePosition pp = new ParsePosition(0);
  Date date = parse(source, pp);
  if (date == null) throw new ParseException(source, pp.getErrorIndex());
  return date;
}

public int sample() {
  return (int) FastMath.round(randomData.nextHypergeometric(populationSize, numberOfSuccesses, sampleSize));
}

public LegendItemCollection getLegendItems() {
  LegendItemCollection result = new LegendItemCollection();
  if (this.plot == null) return result;
  int index = this.plot.getIndexOf(this);
  CategoryDataset dataset = this.plot.getDataset(index);
  if (dataset == null) return result;
  for (int i = 0; i < dataset.getRowCount(); i++) {
    if (isSeriesVisibleInLegend(i)) result.add(getLegendItem(index, i));
  }
  return result;
}

public boolean parse(String source, ParsePosition pos) {
  Matcher matcher = parsePattern.matcher(source.substring(pos.getIndex()));
  if (!matcher.lookingAt()) return false;
  pos.setIndex(pos.getIndex() + matcher.end());
  return true;
}
